/**
 * Request logger middleware.
 * Logs the HTTP method, path, status code, and response time for every request.
 */
function logger(req, res, next) {
  const start = Date.now();

  res.on('finish', () => {
    const duration = Date.now() - start;
    console.log(`${req.method} ${req.path} ${res.statusCode} ${duration}ms`);
  });

  next();
}

module.exports = logger;

/**
 * Centralised error-handling middleware.
 * Must be registered after all routes (four-argument signature tells Express it is an error handler).
 * Formats every error response as: { error: { status, message } }
 */
function errorHandler(err, req, res, next) { // eslint-disable-line no-unused-vars
  const status = err.status || err.statusCode || 500;
  const message = err.message || 'Internal Server Error';

  console.error(`[Error] ${status} - ${message}`);

  res.status(status).json({
    error: {
      status,
      message,
    },
  });
}

module.exports = errorHandler;
